namespace Envoy {
namespace Extensions {
namespace Filters {
namespace Common {
namespace RateLimit {

using RateLimitAsyncCallbacks =
    Grpc::AsyncRequestCallbacks<envoy::service::ratelimit::v3::RateLimitResponse>;

